Type Noeud = Enregistrement
Debut
    valeur  : Entier;
    suivant : ^Noeud;
Fin;

Algorithme Solution_11_Supprimer_Doublons;
Var
    tete, courant, tmp, liste[1000] : ^Noeud;
    Val[1000], index[1000]          : Entier;
    i, N                            : Entier;
Debut
    Lire(N);

    Pour i := 0 a N - 1 Faire
        Lire(Val[i]);
    FinPour

    Pour i := 0 a N - 1 Faire
        Lire(index[i]);
    FinPour

    // 1) Creation des noeuds
    Pour i := 0 a N - 1 Faire
        liste[i] := allouer(Taille(Noeud));
        liste[i]->valeur := Val[i];
    FinPour

    // 2) Etablissement des liens
    Pour i := 0 a N - 1 Faire
        Si index[i] = -1 Alors
            liste[i]->suivant := NIL;
        Sinon
            liste[i]->suivant := liste[index[i]];
        FinSi;
    FinPour

    tete := liste[0];

    // 3) Suppression des doublons (liste triée)
    courant := tete;
    TantQue courant <> NIL ET courant->suivant <> NIL Faire
        Si courant->valeur = courant->suivant->valeur Alors
            tmp := courant->suivant;
            courant->suivant := tmp->suivant;
            liberer(tmp);
        Sinon
            courant := courant->suivant;
        FinSi
    FinTantQue

    // 4) Affichage
    courant := tete;
    TantQue courant <> NIL Faire
        Ecrire(courant->valeur);
        Si courant->suivant <> NIL Alors
            Ecrire(" " );
        FinSi
        courant := courant->suivant;
    FinTantQue
Fin.
